import { describe, expect, it } from 'vitest';
import {
  initAttestationChain,
  attestHop,
  verifyAttestationChain,
  canonicalAttestationBytes,
  summarizeAttestationChain,
  chainMatchesPath,
  type AttestationSigner,
  type AttestationVerifier,
  type ChainBuildContext,
} from './prism-attestation';
import type { PrismPath } from './temporal-prism';

// ─── Test Fixtures ──────────────────────────────────────────────────

// Mock signer: deterministic "signature" = hash(did + message).
// In production this would be bitwise's Ed25519 sign().
function mockSigner(did: string): AttestationSigner {
  return {
    did,
    async sign(message: Uint8Array): Promise<Uint8Array> {
      const sigText = `sig(${did})|${Array.from(message).join(',')}`;
      return new TextEncoder().encode(sigText);
    },
  };
}

// Mock verifier: recomputes the mock signature and compares.
const mockVerifier: AttestationVerifier = {
  async verify(did: string, message: Uint8Array, signature: Uint8Array): Promise<boolean> {
    const expected = `sig(${did})|${Array.from(message).join(',')}`;
    const expectedBytes = new TextEncoder().encode(expected);
    if (signature.length !== expectedBytes.length) return false;
    for (let i = 0; i < signature.length; i++) {
      if (signature[i] !== expectedBytes[i]) return false;
    }
    return true;
  },
};

// Mock hash function: deterministic simple hash.
// In production this would be bitwise's cacheFingerprint64HexFrfSync.
function mockHashFn(data: Uint8Array | string): string {
  const bytes = typeof data === 'string' ? new TextEncoder().encode(data) : data;
  let h = 0;
  for (let i = 0; i < bytes.length; i++) {
    h = (h * 31 + bytes[i]) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}

const ctx: ChainBuildContext = {
  hashFn: mockHashFn,
  verifier: mockVerifier,
};

// Trivial prism path: Earth -> Mars -> Sun
const mockPath: PrismPath = {
  source: 'GnosisTemporalPrism',
  originPidId: 'pid:earth',
  targetPidId: 'pid:sun',
  startEpochMs: 1_000_000,
  deliverAtEpochMs: 1_000_600,
  hops: [
    {
      fromPidId: 'pid:earth', toPidId: 'pid:mars',
      fromLabel: 'Earth', toLabel: 'Mars',
      propagationDelayMs: 300,
      departureEpochMs: 1_000_000, arrivalEpochMs: 1_000_300,
      arrivalPhase: 'rising', phaseScore: 0.9,
    },
    {
      fromPidId: 'pid:mars', toPidId: 'pid:sun',
      fromLabel: 'Mars', toLabel: 'Sun',
      propagationDelayMs: 300,
      departureEpochMs: 1_000_300, arrivalEpochMs: 1_000_600,
      arrivalPhase: 'peak', phaseScore: 0.5,
    },
  ],
  totalDelayMs: 600,
  actualArrivalEpochMs: 1_000_600,
  deliveryErrorMs: 0,
  averagePhaseScore: 0.7,
  onTime: true,
};

// ─── Canonical Serialization ────────────────────────────────────────

describe('canonicalAttestationBytes', () => {
  it('produces deterministic output', () => {
    const a = canonicalAttestationBytes('hash1', null, 1000, 'rising');
    const b = canonicalAttestationBytes('hash1', null, 1000, 'rising');
    expect(Array.from(a)).toEqual(Array.from(b));
  });

  it('different inputs produce different output', () => {
    const a = canonicalAttestationBytes('hash1', null, 1000, 'rising');
    const b = canonicalAttestationBytes('hash1', null, 1001, 'rising');
    expect(Array.from(a)).not.toEqual(Array.from(b));
  });

  it('encodes null previousSignatureHash as literal "null"', () => {
    const bytes = canonicalAttestationBytes('h', null, 1, 'rising');
    expect(new TextDecoder().decode(bytes)).toContain('null');
  });
});

// ─── Chain Construction ────────────────────────────────────────────

describe('initAttestationChain', () => {
  it('creates an empty chain with metadata', () => {
    const chain = initAttestationChain({
      chainId: 'c1',
      originDid: 'did:key:earth',
      targetDid: 'did:key:sun',
      path: mockPath,
      initialPayloadHash: 'payload-hash',
      createdAtPLo: 1000,
    });
    expect(chain.source).toBe('GnosisPrismAttestationChain');
    expect(chain.chainId).toBe('c1');
    expect(chain.hops.length).toBe(0);
    expect(chain.initialPayloadHash).toBe('payload-hash');
    expect(chain.finalPayloadHash).toBe('payload-hash');
  });
});

describe('attestHop', () => {
  it('appends a hop with signature', async () => {
    const chain0 = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    const chain1 = await attestHop({
      chain: chain0,
      signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars',
      attestedAtPLo: 1001,
      attestedPhase: 'rising',
      incomingPayloadHash: 'h0',
      context: ctx,
    });
    expect(chain1.hops.length).toBe(1);
    expect(chain1.hops[0].hopIndex).toBe(0);
    expect(chain1.hops[0].attesterDid).toBe('did:key:mars');
    expect(chain1.hops[0].previousSignatureHash).toBeNull();
  });

  it('chains hops: hop i+1 references hop i signature hash', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    const firstSigHash = mockHashFn(chain.hops[0].signature);
    chain = await attestHop({
      chain, signer: mockSigner('did:key:sun'),
      pidId: 'pid:sun', attestedAtPLo: 1002, attestedPhase: 'peak',
      incomingPayloadHash: 'h0', context: ctx,
    });
    expect(chain.hops[1].previousSignatureHash).toBe(firstSigHash);
  });

  it('tracks transformedHash as finalPayloadHash', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0',
      transformedHash: 'h1',
      context: ctx,
    });
    expect(chain.finalPayloadHash).toBe('h1');
  });

  it('throws if called with null chain', async () => {
    await expect(attestHop({
      chain: null,
      signer: mockSigner('did:key:x'),
      pidId: 'pid:x', attestedAtPLo: 0, attestedPhase: 'rising',
      incomingPayloadHash: 'h', context: ctx,
    })).rejects.toThrow();
  });
});

// ─── Verification ───────────────────────────────────────────────────

describe('verifyAttestationChain', () => {
  async function buildValidChain(): Promise<ReturnType<typeof initAttestationChain>> {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:sun'),
      pidId: 'pid:sun', attestedAtPLo: 1002, attestedPhase: 'peak',
      incomingPayloadHash: 'h0', context: ctx,
    });
    return chain;
  }

  it('verifies a valid chain', async () => {
    const chain = await buildValidChain();
    const result = await verifyAttestationChain(chain, ctx);
    expect(result.valid).toBe(true);
    expect(result.validHops).toBe(2);
    expect(result.invalidHops).toBe(0);
  });

  it('detects tampered signature', async () => {
    const chain = await buildValidChain();
    const tampered = {
      ...chain,
      hops: [
        { ...chain.hops[0], signature: new Uint8Array([99, 99, 99]) },
        chain.hops[1],
      ],
    };
    const result = await verifyAttestationChain(tampered, ctx);
    expect(result.valid).toBe(false);
    expect(result.invalidHops).toBeGreaterThanOrEqual(1);
  });

  it('detects broken chain link', async () => {
    const chain = await buildValidChain();
    const broken = {
      ...chain,
      hops: [
        chain.hops[0],
        { ...chain.hops[1], previousSignatureHash: 'wrong-hash' },
      ],
    };
    const result = await verifyAttestationChain(broken, ctx);
    expect(result.valid).toBe(false);
    expect(result.hopResults[1].chainLinkValid).toBe(false);
  });

  it('detects out-of-order timestamps', async () => {
    const chain = await buildValidChain();
    const reordered = {
      ...chain,
      hops: [
        chain.hops[0],
        { ...chain.hops[1], attestedAtPLo: 500 }, // before first hop
      ],
    };
    const result = await verifyAttestationChain(reordered, ctx);
    expect(result.hopResults[1].phaseConsistent).toBe(false);
  });

  it('empty chain is not valid', async () => {
    const empty = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    const result = await verifyAttestationChain(empty, ctx);
    expect(result.valid).toBe(false);
    expect(result.totalHops).toBe(0);
  });
});

// ─── Analysis ───────────────────────────────────────────────────────

describe('summarizeAttestationChain', () => {
  it('counts distinct attesters and tracks timing', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:sun'),
      pidId: 'pid:sun', attestedAtPLo: 1005, attestedPhase: 'peak',
      incomingPayloadHash: 'h0', context: ctx,
    });

    const summary = summarizeAttestationChain(chain);
    expect(summary.hopCount).toBe(2);
    expect(summary.distinctAttesters).toBe(2);
    expect(summary.firstAttestationPLo).toBe(1001);
    expect(summary.lastAttestationPLo).toBe(1005);
    expect(summary.elapsedPLo).toBe(4);
    expect(summary.payloadTransformed).toBe(false);
  });

  it('detects payload transformation', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', transformedHash: 'h1', context: ctx,
    });
    const summary = summarizeAttestationChain(chain);
    expect(summary.payloadTransformed).toBe(true);
  });

  it('tracks phase distribution', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:sun'),
      pidId: 'pid:sun', attestedAtPLo: 1002, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    const summary = summarizeAttestationChain(chain);
    expect(summary.phaseDistribution['rising']).toBe(2);
  });
});

describe('chainMatchesPath', () => {
  it('matches when chain hops align with path hops', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:mars'),
      pidId: 'pid:mars', attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:sun'),
      pidId: 'pid:sun', attestedAtPLo: 1002, attestedPhase: 'peak',
      incomingPayloadHash: 'h0', context: ctx,
    });
    const result = chainMatchesPath(chain, mockPath);
    expect(result.matches).toBe(true);
    expect(result.mismatches.length).toBe(0);
  });

  it('detects PID mismatch at a specific index', async () => {
    let chain = initAttestationChain({
      chainId: 'c1', originDid: 'did:key:earth', targetDid: 'did:key:sun',
      path: mockPath, initialPayloadHash: 'h0', createdAtPLo: 1000,
    });
    chain = await attestHop({
      chain, signer: mockSigner('did:key:jupiter'),
      pidId: 'pid:jupiter', // NOT on the path
      attestedAtPLo: 1001, attestedPhase: 'rising',
      incomingPayloadHash: 'h0', context: ctx,
    });
    const result = chainMatchesPath(chain, mockPath);
    expect(result.matches).toBe(false);
    expect(result.mismatches).toContain(0);
  });
});
